@ARTICLE{10.3332/ecancer.2025.2044,
	author = {Gómez Calcetero C and Granados Diaz J and Aya Porto A and Forero Romero A, López Mora M, Omaña Orduz P and Daza Buitrago J and Murcia Linares M and Abello Polo V},
	title = {Short and long term central peripherally inserted catheters in hematological malignancy patients: clinical outcomes and safety. Single centre experience.},
	journal = {Ecancermedicalscience},
	year = {2025},
	abstract = {OBJECTIVE: To characterise the population and describe the complications in patients with hematologic malignancies who underwent implantation of a peripherally inserted central catheter (PICC) or midline catheter (MC) for the administration of chemotherapy or oncologic support. METHODS: The retrospective descriptive study included patients with hematologic malignancies who underwent PICC or MC implantation between July 2022 and 2024. All patients are part of the institution-based prospective observational Evidence - Verification - Analysis study. Variables related to device type were obtained from the vascular access and infection control group databases. Frequencies and percentages were used for categorical variables, and medians and interquartile ranges were used for numerical variables. Event rates per 1,000 days were calculated for complications. RESULTS: 156 patients with 249 events were included. All devices were high-flow and bi-lumen, the most common indication was chemotherapy administration, and the most common site was brachial. The median days in use for lymphoma and acute leukaemia were 67.5 and 24 days, respectively. The rates of catheter-associated thrombosis and catheter-associated bloodstream infection were 3.2% and 3.7%, respectively. The rates of catheter-related venous thrombosis per 1,000 catheter days and catheter-related bloodstream infection per 1,000 catheter days were 0.31 and 0.83, respectively. CONCLUSION: A multidisciplinary approach, thorough initial venous assessment, a strong support network, adherence to care protocols and continuous patient education have helped to reduce variability in care and lower complication rates at our institution.},
	doi = {10.3332/ecancer.2025.2044},
	pmid = {41778187},
	note = {PMC12950876}
}

@ARTICLE{10.3389/fonc.2026.1714656,
	author = {Haj D and Said M and Al-Assil T and Stone S and Omaira M},
	title = {Richter transformation to classical Hodgkin lymphoma following recurrent disseminated histoplasmosis in chronic lymphocytic leukemia: a Case Report.},
	abstract = {BACKGROUND: Richter Transformation (RT) is the rare progression of chronic lymphocytic leukemia/small lymphocytic lymphoma (CLL/SLL) into a more aggressive lymphoma, occurring in only about 5-10% of cases. RT has a poor prognosis with rapid progression and resistance to standard therapies. PET/CT scans are crucial in detecting RT with increased SUVmax indicating more aggressive disease. CASE PRESENTATION: A 65-year-old male with 13q deletion CLL developed three relapses over the course of 13 years from initial CLL diagnosis, and work up of the third relapse revealed disseminated histoplasmosis. He improved with Ibrutinib for CLL and Amphotericin B for histoplasmosis. Four and seven years later, the patient re-presented with histoplasmosis reinfections, confirmed by PET/CT and biopsy, and treated with antifungals for each reinfection. One year later (21 years from initial CLL diagnosis), he presented with malignant hypercalcemia and retroperitoneal lymphadenopathy (LAD) for which biopsy revealed RT to classic Hodgkin's Lymphoma (cHL). Given his impaired renal function, his treatment regimen included AVD chemotherapy and nivolumab, from which he eventually recovered. DISCUSSION/CONCLUSION: CLL patients are inherently immunocompromised due to hypogammaglobulinemia, increasing their susceptibility to opportunistic infections like histoplasmosis. These infections can recur, be refractory, and may even coincide with RT. This unusual case of RT after chronic disseminated histoplasmosis reinfections involved lymph nodes and eventually hypercalcemia. Vigilant monitoring and patient education on risk avoidance are recommended strategies for mitigating risk of histoplasmosis. Providers may also consider Itraconazole prophylaxis. Further research is warranted to better understand the relationship between chronic opportunistic infections and the oncogenic progressions in CLL patients.},
	doi = {10.3389/fonc.2026.1714656},
	pmid = {41777646},
	note = {PMC12950534}
}

@ARTICLE{10.1002/cam4.71457,
	author = {Warnakulasuriya H and Tiwari R},
	title = {Racial and Socioeconomic Healthcare Disparities in Access to Chimeric Antigen Receptor T (CAR-T) Cell Therapy for Blood Cancers.},
	journal = {Cancer Med},
	year = {2026},
	abstract = {BACKGROUND: Health disparities remain a critical global public health challenge, particularly in access to advanced treatments for blood cancers. Racial and socioeconomic factors influence healthcare accessibility, contributing to inequities in patient outcomes. Despite the potential of CAR-T therapy in treating blood cancers, disparities in financial resources, education, gender, and race hinder equitable access. This study evaluates literature on CAR-T therapy to identify access disparities and proposes policy recommendations. METHODS: The PRISMA-ScR guidelines were followed for study selection and reporting. A comprehensive search strategy was used across databases like PubMed and Google Scholar, using keywords and MeSH terms. Inclusion criteria included peer-reviewed studies in English since 2000. A basic quality appraisal was conducted to ensure the relevance and credibility of included studies, despite the diversity of study designs and the primary focus on mapping key themes across the literature. RESULTS: Twenty-five relevant (25) studies, including analytical studies, observational studies, and literature reviews, were analyzed. Findings indicate significant racial and socioeconomic disparities in CAR-T therapy accessibility, with financial constraints, lack of awareness, and systemic biases limiting equitable distribution. Challenges include high treatment costs, lack of insurance coverage, and underrepresentation of minority groups in trials. CONCLUSION: Addressing these disparities requires targeted policy interventions, increased funding, and improved patient education. Continued research and collaboration are essential to ensure equitable access for all individuals.},
	doi = {10.1002/cam4.71457},
	pmid = {41651454 [Indexed for MEDLINE]},
	note = {PMC12880879}
}

@ARTICLE{10.3389/fmed.2025.1657054,
	author = {Glonnegger H and Boeckelmann D, Wiedenhöfer R and Hassenpflug WA and Ripperger T and Lebrecht D, Knöfler R and Tiebel O and Koehler U and Wehr C and Sirb H and Sparber-Sauer M and Reinsberger K and Yoshimi A and Strahm B and Zieger B},
	title = {RUNX1-FPDMM in families with mild thrombocytopenia and platelet function anomalies: a case series.},
	journal = {Front Med (Lausanne)},
	year = {2025},
	abstract = {BACKGROUND: RUNX1-familial platelet disorder with associated myeloid malignancy (RUNX1-FPDMM) is caused by heterozygous germline variants of RUNX1. With the broader application of next-generation sequencing (NGS)-based gene panel analysis in individuals presenting with benign hematologic abnormalities such as thrombocytopenia, pathogenic RUNX1 variants were more frequently identified, independent of a hematologic malignancy. OBJECTIVE: This study aimed to describe the clinical and genetic characteristics of individuals with pathogenic germline RUNX1 variants, with a particular focus on platelet function and diagnostic challenges. METHODS: We retrospectively analyzed 10 individuals from 6 families with genetically confirmed RUNX1-FPDMM. Platelet counts and function were evaluated using light transmission aggregometry (LTA) and flow cytometry (FC). For genetic analysis, NGS-based panel sequencing for inherited platelet disorders, Sanger sequencing, karyotyping, fluorescence in situ hybridization (FISH), and microarray analysis were performed. RESULTS: Platelet counts ranged between 40 and 208 G/L. In all six tested individuals, LTA revealed impaired aggregation in response to collagen, adenosine diphosphate (ADP), and epinephrine. FC analysis identified a pronounced granule secretion defect in three of the eight tested individuals. Disease-causing RUNX1 variants included whole-gene or intragenic deletions, one missense, two not previously reported non-sense variants, and a mosaic RUNX1 loss most probably due to the loss of a derivative chromosome 21. One patient has developed acute myeloid leukemia (AML), and another was diagnosed with RUNX1-FPDMM due to thrombocytopenia onset following T-lymphoblastic lymphoma. CONCLUSION: RUNX1-FPDMM is a challenging disease due to its associated increased risk for hematologic malignancies, mainly myelodysplastic syndrome (MDS) or AML. Genetic diagnosis in individuals with thrombocytopenia or functional platelet defects of unknown origin is crucial to offer structured surveillance and patient education. Increased risk of bleeding due to qualitative platelet function defects, particularly granule secretion abnormalities, must be considered when managing patients, especially prior to invasive procedures.},
	doi = {10.3389/fmed.2025.1657054},
	pmid = {41458504},
	note = {PMC12739554}
}

@ARTICLE{10.1016/j.rcsop.2025.100678,
	author = {Moritz AK and Fehrmann W and Schuler MK and Stock S and Jaehde U and Ernstmann N},
	title = {Unmet information needs and knowledge gaps in cancer patients undergoing oral anticancer therapy.},
	journal = {Explor Res Clin Soc Pharm},
	year = {2025},
	abstract = {BACKGROUND: The increasing use of oral anticancer therapy (OAT) requires self-management skills from cancer patients. Adequate information and counseling, as well as medication literacy, are key elements of safe and successful therapy in the patient's home. OBJECTIVE: The aim of the study was to identify unmet information needs and knowledge gaps of cancer patients regarding their therapy with OAT. METHODS: Semi-structured, guideline-based interviews with cancer patients undergoing OAT were conducted, recorded and professionally transcribed. The transcripts were analysed using qualitative content analysis. RESULTS: A total of 21 interviews were conducted. Fifteen of the interviewees were female, the median age was 69.6 years. Patients with solid tumours as well as those with blood cancers were interviewed. In the interviews, experiences were reported with various classes of OATs (chemotherapy; anti-hormonal therapy; targeted therapy). The following themes were identified: 1) Therapy-related information needs; 2) No information received; 3) No awareness for information needs; 4) No need for more information; 5) Therapy-related knowledge gaps; 6) Potentially inadequate knowledge. Deficits were identified in relation to correct use, possible interactions, and dealing with adverse events. Individual patients also report actively avoiding information. CONCLUSION: The identified information needs and knowledge gaps of patients undergoing OAT highlight the need to optimize information and counseling in order to ensure treatment safety and success. In addition to providing knowledge, the self-management skills of patients should also be specifically strengthened. Furthermore, improvements to the structural framework in the outpatient setting are necessary, particularly with regard to the availability of counseling services. The results can be used as a basis for the development of specific interprofessional educational interventions for those affected.},
	doi = {10.1016/j.rcsop.2025.100678},
	pmid = {41425733},
	note = {PMC12712599}
}

@ARTICLE{10.1186/s12891-025-09405-1,
	author = {Talebian P and Soleimani M and Mottahedi M and Nazar E and Shahbazi P},
	title = {Orthopedic manifestations of acquired hemophilia: a case report on uncontrolled bleeding and progressive swelling post-phlebotomy- should fasciotomy be considered?},
	journal = {BMC Musculoskelet Disord},
	year = {2025},
	abstract = {BACKGROUND: Acquired hemophilia A (AHA) is a rare bleeding disorder caused by autoantibodies against clotting factors, often resulting in spontaneous bleeding or bleeding after minor trauma, potentially leading to Acute Compartment Syndrome (ACS). Diagnosing and managing AHA-induced ACS is challenging due to its rarity and the risks associated with fasciotomy in bleeding disorders. In low- and middle-income countries (LMICs), ACS management is further complicated by the lack of intra-compartmental pressure monitoring devices, necessitating reliance on clinical symptoms. CASE PRESENTATION: A 36-year-old woman presented to the emergency department with progressive swelling of the left antecubital area after phlebotomy with no trauma or bleeding disorder history. After hospitalization a venous color Doppler ultrasound showed superficial vein thrombosis, and the patient was discharged and referred to the orthopedic service for follow-up of clinical symptoms. Returned to the hospital after approximately six hours due to the development of generalized weakness and hemodynamic instability. Diagnostic challenges arose as initial laboratory results suggested possible acute leukemia due to leukocytosis and thrombocytosis. Her condition deteriorated rapidly with wrist drop which drew increased attention and necessitating a fasciotomy due to suspected ACS, revealing profuse bleeding. Subsequent tests revealed low factor VIII levels and a high factor VIII inhibitor, confirming AHA. Treatment included empirically activated factor VII, prednisolone, cyclophosphamide, and rituximab, resulting in gradual improvement but residual wrist drop. CONCLUSIONS: This case underscores the importance of considering AHA in patients with ACS-like symptoms and unexplained prolonged activated Partial Thromboplastin Time (aPTT), even without bleeding history. It also highlights the need to investigate any unexplained aPTT prolongation before surgical interventions. Collaboration between orthopedic surgeons and hematologists is essential for optimizing outcomes. Approaching to algorithms for non-traumatic ACS in AHA is an important step. Prompt intervention, patient education, and tailored treatment strategies are crucial for preventing severe complications and optimizing patient outcomes.},
	doi = {10.1186/s12891-025-09405-1},
	pmid = {41413513 [Indexed for MEDLINE]},
	note = {PMC12831262}
}

@ARTICLE{10.1186/s12885-025-15301-7,
	author = {Falahan SN and Mohammadi R and Ayubi E and Yousofvand V},
	title = {Comparing the effects of pictorial and Teach-Back education methods on self-efficacy and quality of life in patients with leukemia: a randomized controlled trial.},
	journal = {BMC Cancer},
	year = {2025},
	abstract = {BACKGROUND: Leukemia patients often experience reduced self-efficacy and impaired quality of life. Effective education can help improve these outcomes. This study aimed to compare the effects of the Teach-Back and pictorial education methods on self-efficacy and quality of life among patients with leukemia. METHODS: This three-arm randomized controlled trial was conducted on 90 Leukemia patients at the Oncology Clinic of Shahid Beheshti Hospital, Hamadan, Iran, during 2023 and 2024. Participants were randomly assigned to one of three groups: Teach-Back education, pictorial education, and control. Both intervention groups received eight weekly sessions of 45 to 60 min, providing similar educational content regarding disease nature, symptom management, and coping skills. Data were collected using the Sherer General Self-Efficacy Scale and the European Organization for Research and Treatment of Cancer Quality of Life Questionnaire (EORTC QLQ-C30) at baseline, one month, and two months post-intervention. RESULTS: Post-intervention, both educational methods significantly enhanced self-efficacy, overall quality of life, and multiple subdomains compared to the control group (P < 0.001). Nevertheless, the Teach-Back method appeared to be more effective than pictorial education and routine care across most domains and symptoms, including fatigue, pain, nausea/vomiting, dyspnea, sleep disturbances, constipation, diarrhea, and appetite loss. Between-group effect sizes were moderate and statistically significant for self-efficacy (η2 = 0.494) and quality of life (η2 = 0.522). These improvements were sustained at the two-month follow-up. CONCLUSION: Based on the findings of this study, it is recommended that the Teach-Back method be implemented by healthcare providers, particularly nurses, within care programs for patients with leukemia. TRIAL REGISTRATION NUMBER: IRCT20211227053551N3; Registration Date: 2022-11-26.},
	doi = {10.1186/s12885-025-15301-7},
	pmid = {41327104},
	note = {PMC12667168}
}

